-- ── Datasette ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Datasette is a free, open-source tool by Simon Willison for exploring, querying, and publishing SQLite databases as interactive websites with a built-in JSON API.$q$, short_description),
  pricing_model = COALESCE($q$Free / Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2017, founded_year),
  company_size = COALESCE($q$Small (independent open-source project)$q$, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Datasette: Open-Source SQLite Data Exploration Tool$q$, seo_title),
  seo_meta_description = COALESCE($q$Datasette is a free, open-source tool by Simon Willison for exploring and publishing SQLite data as websites and APIs. See features, plugins, and pricing.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Datasette is an open-source multi-tool for exploring and publishing data, built around SQLite, that lets anyone take a dataset of almost any size or shape and turn it into an interactive, browsable website with an accompanying JSON API, without writing a custom web application. It was created by Simon Willison, a programmer and writer best known as a co-creator of the Django web framework, who began the Datasette project in 2017 as a way to make it dramatically easier for data journalists, researchers, and civic technologists to publish structured data online in a form the public could actually query and explore rather than downloading a static spreadsheet. Datasette is written in Python and distributed as free, open-source software, and its source code is hosted publicly on GitHub under the simonw organization, where Willison continues to actively maintain it alongside a related family of tools, including sqlite-utils, a Python library and command-line utility for manipulating SQLite databases, and the llm command-line tool for interacting with large language models. Architecturally, Datasette works by pointing at one or more SQLite database files and automatically generating a browsable web interface: every table becomes an explorable, filterable, sortable page, every individual row is assigned its own stable URL, and any foreign-key relationships between tables are automatically surfaced as links, letting a user click from a row in one table to every row in another table that references it. Every page and query in the interface is also available as JSON through Datasette's built-in API, meaning any exploration a human does through the browser can equally be scripted or consumed programmatically, and custom SQL queries can be run directly against the underlying data (in a safely sandboxed, read-only way for published sites) and bookmarked or shared as a URL. Because SQLite databases are simple, portable files, Datasette instances are easy to deploy: the project includes tooling to publish one or more databases to hosting platforms like Google Cloud Run, Vercel, Fly.io, or Heroku with a single command, and the project also ships Datasette Lite, a version of Datasette compiled to WebAssembly that runs entirely inside a web browser using Pyodide, requiring no server or backend at all, which is particularly useful for quick, shareable data explorations that need zero hosting infrastructure. A large part of Datasette's power comes from its plugin architecture: the project maintains a directory of more than eighty community-built plugins that extend its core functionality, covering areas like authentication, full-text search, geographic and mapping visualizations, charting, CSV and Excel export, and integrations with cloud storage and AI tools, which lets Datasette's relatively small, focused core stay simple while still supporting a wide range of specialized use cases. Willison has also built Datasette Cloud, a hosted, managed version of Datasette aimed at making the tool accessible to non-technical users such as journalists who do not want to self-host or manage a server, a project that received sponsorship support from the infrastructure company Fly.io. Datasette does not have a traditional commercial pricing structure for the core open-source tool itself; anyone can download, self-host, and use it for free, and it carries no license fees, while Datasette Cloud, where it is offered, functions as a separately hosted service. In terms of target audience, Datasette is explicitly aimed at data journalists who need to publish investigative datasets alongside a news story, museum curators and archivists digitizing and sharing collections data, local and civic governments publishing open data, scientists and researchers making datasets available to peers, and software engineers who simply want a fast way to explore and query a CSV or database dump without spinning up a full database server or BI tool. Compared to full business intelligence platforms like Metabase, Redash, or Apache Superset, which are designed primarily for internal dashboarding against production databases, Datasette is lighter-weight, focuses specifically on SQLite as its storage format, and emphasizes public, read-only publishing of static or slowly changing datasets rather than live operational dashboards; this makes it a poor fit for real-time transactional data but an excellent fit for archival, investigative, and reference datasets that benefit from being permanently and openly queryable. Notable facts about the project include that it has become closely associated with the broader 'data journalism' and civic tech communities, has been used to publish datasets tied to investigative reporting projects, and that Willison has increasingly connected Datasette to his more recent work on large language model tooling, exploring ways that LLMs can generate SQL queries or summarize data explored through Datasette, reflecting the project's ongoing evolution alongside the broader AI tooling ecosystem while remaining fundamentally a free, community-driven, open-source project rather than a venture-backed company. Because Datasette treats structured data as something meant to be published on the open web rather than locked inside a private dashboard, it has become a reference example in discussions about small, sustainable, independently maintained open-source tools that nonetheless see meaningful real-world adoption without a corporate backer or funding round behind them.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'd9436d03-14e1-4e93-969b-27951c8697e7';

